import React from 'react'
import type { ISiteContext } from './site'
import { SiteContextType } from './site'

export interface IDependencyContext {
  useSiteStore: ISiteContext['useSiteStore']
}

export const useDependencyContext = (): IDependencyContext => {
  const { useSiteStore } = React.useContext(SiteContextType)
  return { useSiteStore }
}
