import React from 'react'
import type { IStorage } from '../types'

export function useInitialData<T extends Record<string, unknown>>(
  storage: IStorage<T> | null,
  defaultData: T,
): T | null {
  const [initialData, setInitialData] = React.useState<T | null>(null)

  React.useEffect(() => {
    let cancelled = false
    void storage
      ?.load()
      .then(data => {
        if (!cancelled) setInitialData({ ...data, ...defaultData })
      })
      .catch(error => {
        console.error(error)
        if (!cancelled) setInitialData({ ...defaultData })
      })

    return () => {
      cancelled = true
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [storage])

  return initialData
}
