import { ThemeProvider as MuiThemeProvider, createTheme } from '@mui/material'
import { Theme, ThemeProvider as YozoraThemeProvider } from '@yozora/core-react-theme'
import React from 'react'
import shallow from 'zustand/shallow'
import { useDependencyContext } from '@/core/context'

const muiDarkTheme = createTheme({ palette: { mode: 'dark' } })
const muiLightTheme = createTheme({ palette: { mode: 'light' } })
export const ThemeProvider: React.FC<{ children: React.ReactNode }> = props => {
  const { useSiteStore } = useDependencyContext()
  const [theme] = useSiteStore(({ state }) => [state.preference.theme], shallow)
  return (
    <MuiThemeProvider theme={theme === Theme.DARKEN ? muiDarkTheme : muiLightTheme}>
      <YozoraThemeProvider theme={theme}>{props.children}</YozoraThemeProvider>
    </MuiThemeProvider>
  )
}
